  if(o.communication?.status)$('#detailPanel .detail-top').insertAdjacentHTML('afterend',`<div class="application-route"><b>Communication:</b> ${esc(o.communication.status)}${o.communication.followUpDate?` · Follow up ${esc(o.communication.followUpDate)}`:''}</div>`);
