$('#exportCsv').onclick=()=>{const headers=['Platform','Client','Country','Project title','Opportunity type','Match score','Budget','Currency','Status','Communication status','Follow-up date','Follow-up state','Last contacted','Reply received','Notes'];const rows=realOpportunities().map(o=>[o.platform,o.client,o.country,o.title,o.type,window.RoleDeskTracker.matchScore(o),window.RoleDeskTracker.amount(o)||'',window.RoleDeskTracker.currency(o),trackerStatus(o),o.communication?.status||'',o.followup?.nextAt||o.communication?.followUpDate||'',trackerFollowup(o),o.lastContactedAt||'',o.replyReceivedAt||'',o.followup?.notes||o.notes||'']);const csv=[headers,...rows].map(r=>r.map(v=>`"${String(v??'').replaceAll('"','""')}"`).join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='roledesk-opportunity-tracker.csv';a.click();URL.revokeObjectURL(a.href);toast('RoleDesk tracker exported')};
